var b="url",c="物料退货单.html",d="generationDate",e=new Date(1781588963000.94),f="defaultAdaptiveView",g="name",h="",i="size",j="width",k=0,l="height",m="adaptiveViews",n="sketchKeys",o="s0",p="variables",q="OnLoadVariable",r="page",s="packageId",t="461aab10749d47c781503c28cf39a53a",u="type",v="Axure:Page",w="物料退货单",x="notes",y="annotations",z="fn",A="1",B="ownerId",C="87a5581d4ded439d81a52da6837ca956",D="label",E="(下拉列表)",F="说明",G="<p><span style=\"color:#333333;\">1.提示字：请选择状态</span></p><p><span style=\"color:#333333;\">2.可选项：①未开始②出库中③已完成</span></p><p><span style=\"color:#333333;\">3.选中后立即返回筛选结果</span></p><p><span style=\"color:#333333;\">4.右侧包含&quot;×&quot;的快捷清除按钮</span></p>",H="2",I="3ce069e050434482a6a269048a0a1304",J="状态",K="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">1.状态</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp;&nbsp; a.未开始</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp;&nbsp; b.出库中</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp;&nbsp; c.已完成</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">2.状态流转</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp;&nbsp; a.生成采购单，初始状态“未开始”’</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp;&nbsp; b.累计已出库数量大于0，采购单状态变更成“出库中”</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; &nbsp;&nbsp; c.退货单下全部物料的状态为完成，采购单状态变更成“已完成”</span></p>",L="3",M="2f38d91d10f54b8299bc2b8eac137030",N="确认",O="<p><span>1.校验累计的“本次退货数量”须＞0；否则Toast提示：退货数量须大于0</span></p><p><span>2.校验全部行的“入库数量”≥“本次退货”；否则Toast提示：退货数量超出入库数量</span></p><p><span>3.校验全部行的“库存数量”≥“本次退货”；否则Toast提示：退货数量不能大于库存数量</span></p><p><span>4.若“退货类型”为</span><span style=\"color:#02A7F0;\">退货入库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.创建新的采购退款单(CGTH)，状态初始化为“</span><span style=\"color:#D9001B;\">未开始</span><span>”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.新增出库任务单(CKRW)至出库任务操作</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.出库类型：退货出库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.关联单号：对应的“采购退货单号”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iii.生产订单、自定义单号、款号、图片、属主、仓库：均取对应'采购订单'上的信息</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; iv.退货清单：以当前弹窗内“本次退货数量”＞0的行作为退货SKU</span></p><p><span>5.若“退货类型”为</span><span style=\"color:#02A7F0;\">红冲入库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; a.再次校验其仓库-属主-库存足以被扣除；否则Toast提示：退货数量不能大于库存数量</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; b.创建新的采购退款单(CGTH)，状态初始化为“</span><span style=\"color:#D9001B;\">已完成</span><span>”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; c.以按量拣货逻辑对SKU的批次码进行出库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.先查出退货单对应采购单是否关联生产订单/版单/款号①生产订单/版单、款号绑定一致的库存 ②生产订单绑定一致的库存 ③款号绑定一致的库存④未被绑定的库存</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.库存扣除</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; d.创建[入库单]</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.入库单编号规则：'RKD'+'6位年月日'+'2位流水'，例：RKD23073101</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.入库类型：红冲入库</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ① 关联业务：当前“调拨单号”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ② 操作人、操作日期：取当前操作人和日期(年-月-日)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ③ 其它字段为空</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; e.将批次码的入库情况记录至[入库单]详情中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ① 记录字段：批次码、物料编码、物料名称、颜色、规格/门幅、</span><span style=\"color:#8400FF;\">数量</span><span>、单位</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ② 其中：</span><span style=\"color:#8400FF;\">数量为负数</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; f.将批次码的入库情况记录至[入库明细]报表中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; g.将批次码的入库情况记录至[出入库明细]报表中</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.出入库筛选时，属于“入库”</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; ii.关联单号是“采购退货单”(CGTH)</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; h.数值进入[订单进销存]和[物料进销存]</span></p><p><span>&nbsp;&nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;&nbsp; i.数据累计至“入库数量”而不是累计“退货数量”</span></p>",P="4",Q="1a0c0726148e4595973ba61ab9e45a94",R="已出库数量",S="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">每次出库拣货就会有个对应的复核单，复核单通过后累计至已出库数量</span></p>",T="5",U="ffe75f18d9b244a2a79777020e313a20",V="<p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">单个物料出库状态：</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; ①已出库数量 ≥ 退货数量：完成</span></p><p><span style=\"font-family:'Arial Normal', 'Arial', sans-serif;color:#333333;\">&nbsp;&nbsp; ②已出库数量＜退货数量：未完成</span></p>",W="6",X="07effdb0acf5459f9c73a08def5e4882",Y="* 退货类型：",Z="<p><span>1.可选项：①退货出库 ②红冲入库</span></p><p><span>2.根据配置读取默认值</span></p>",ba="7",bb="bfd55047831d4f58ab62aebd0b6f3bd6",bc="* 采购单号：",bd="<p><span>1.结果仅可下拉选择，不可手写</span></p><p><span>2.数据源：①CGDD ②WLCG</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.支持模糊搜索“采购订单号”或“供应商名称”</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.选择后仅返回“采购订单号”</span></p><p><span>3.根据选择的采购订单号展示对应的“生产订单”和“生产款号”</span></p>",be="8",bf="8ca6799c9b7a481ca2e5a43b909f9dff",bg="生产订单：",bh="<p><span>跟随选中的“采购单号”</span></p>",bi="9",bj="58aebc978f85400ea1d01757058b8c0b",bk="生产款号：",bl="10",bm="890a592271674123927b28e59e01a769",bn="<p><span>1.校验该“采购订单”生成入库任务状态</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.已生成：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.未生成：校验失败，Toast提示：未入库的采购订单，无须退货</span></p><p><span>2.校验该“采购订单”是否已经生成[采购结算单]</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; a.未生成：通过校验</span></p><p><span>&nbsp;&nbsp; &nbsp;&nbsp; b.已生成：校验失败，Toast提示：该采购订单已结算，无法发起采购退货单</span></p><p><span>3.通过全部校验，弹窗填写退货清单</span></p>",bo="style",bp="baseStyle",bq="627587b6038d43cca051c114ac41ad32",br="pageAlignment",bs="center",bt="fill",bu="fillType",bv="solid",bw="color",bx=0xFFFFFFFF,by="image",bz="imageAlignment",bA="near",bB="imageRepeat",bC="auto",bD="favicon",bE="sketchFactor",bF="0",bG="colorStyle",bH="appliedColor",bI="fontName",bJ="Applied Font",bK="borderWidth",bL="borderVisibility",bM="borderFill",bN=0xFF797979,bO="cornerRadius",bP="cornerVisibility",bQ="outerShadow",bR="on",bS=false,bT="offsetX",bU=5,bV="offsetY",bW="blurRadius",bX="spread",bY="r",bZ=0,ca="g",cb="b",cc="a",cd=0.349019607843137,ce="adaptiveStyles",cf="interactionMap",cg="diagram",ch="objects",ci="id",cj="a3e5933383c94354b2409e4222f934a6",ck="friendlyType",cl="标题-1340",cm="referenceDiagramObject",cn="styleType",co="visible",cp=true,cq=1340,cr=110,cs="imageOverrides",ct="masterId",cu="bdaeed3774644546913b266f76aa115f",cv="1d3d4dbfc2364c388f0c50b709a64c3c",cw="分页",cx=260,cy=28,cz="location",cA="x",cB=20,cC="y",cD=382,cE="0371b246be61404f9f94b1190e8d1f3d",cF="dd5bb6f258574435b1d943590d720010",cG="表格",cH="table",cI=1320,cJ=160,cK=196,cL="1e7bf4f2f3184dfb98b4ff3816958d7c",cM="单元格",cN="tableCell",cO="fontWeight",cP="700",cQ="foreGroundFill",cR=0xFF3399FF,cS="opacity",cT=1,cU=164,cV=40,cW="2b919df770544924b45cd529b520fb2f",cX="fontSize",cY="14px",cZ=0xFFD7D7D7,da="images",db="normal~",dc="images/物料退货单/u7465.png",dd="6ffb2062c82b43839adeb7b297402ce2",de=80,df="931f16b4ca884d6ea078710350071488",dg